VALUES
  ('social-worker-moex-06120', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '一位社區工作者想要瞭解社區居民有無參與「照顧社區中失能長者之教育性講座」的需求，他透過分析 目前在社區中各個相關福利機構過去與現在提供服務的相關資料、以及訪問福利機構的工作人員與董監 事會成員，來進行社區需求的評估（community need assessment），他所使用的是下列那一項社區需求評 估的技術？', '["社會及健康指標分析（social and health indicator analysis）", "得爾菲法（Delphi approach）", "社區論壇（community forum）", "分析服務的需要（demands for services）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06121', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作人員進行社區工作時，不扮演何種角色？', '["組織者", "倡導者", "訓練者", "治療者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06122', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列有關美國社區睦鄰中心的敘述，何者錯誤？', '["美國第一個社區睦鄰中心成立於西元1886年", "美國第一個社區睦鄰中心是湯恩比館（Toynbee Hall）", "亞當斯（J. Adams）於1889年在芝加哥創立了赫爾館（Hull House）", "赫爾館主要的工作項目包括各式各樣的社會服務與社會改革"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06123', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是社區工作的原則？', '["瞭解社區資訊並評估社區需求", "社區人才訓練", "資源開發", "不強調永續經營"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06124', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「個案管理」（case management）可被視為在執行社區照顧過程中，連結各項服務資源的工作方法。請 問下列有關個案管理的敘述，何者錯誤？', '["個案管理重視正式與非正式資源的連結與開發", "個案管理主要針對社會政策的不合理之處，為服務對象進行倡導（advocacy），其工作重點不包括對於 服務對象在過程中的情緒受挫或心理問題，提供諮商（counseling）、治療（therapy）等服務", "個案管理者面對部分案主缺乏服務資源的狀態時，需要運用相關技巧，開發新的服務資源", "個案管理的服務對象來源，可能包括自行求助、轉介或是透過外展服務發現的自願與非自願案主"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06125', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作者應具備多元的專業能力，其中一項能力為「促進與使能」，關於這項專業能力的敘述，何者 錯誤？', '["社區工作者應該在執行計畫中，具有因應突發困難及與社區居民溝通的能力", "社區工作者應該引發社區居民關心社區事務，凝聚對社區的認同", "社區工作者應該增進社區居民面對問題的解決能力，並能發揮自身所長", "社區工作者應該協助社區居民參與各項社區事務，並能在相關活動中表達自身的想法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06126', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區產業（community enterprise）係指以社區生活共同體為基礎所發展出來的產業。社區產業因為特質不 同，分為許多類型。「臺灣有許多社區以生態特色發展民宿，居民乃組成生態保護團體，以維持社區生 態及有力於民宿支持」。關於上述社區產業的敘述，何者正確？', '["在一定的空間內，存在相同的產業經濟活動，且這些經濟活動不但相對於其他的地區具有特性，且從 業者組成合作、自治性的組織，以促進該等產業的發展", "由社區組織所經營的產業", "在一定的空間中，居民從事相同的產業經濟活動，且相對於其他地區具有獨特性", "社區居民基於運用社區的公共財，而開創活化經濟活動的產業，並組織持續維護該公共財，以利居民 個人產業的經營"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06127', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '一位社區工作者為了協助社區居民獲得有關失能長者居家照顧之知能，邀請社區內部與外部在協助失能 長者有學理及實務運作經驗的專家學者，組成該社區的「失能長者居家照顧專業諮詢團隊」。他所使用 的是下列那項社區工作實務技術？', '["社區宣導", "資源動員", "意識覺醒", "資源配置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06128', 'social-worker', 'social-worker-moex-104-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者不是社區工作的起源？', '["德國的愛伯福制度（Elberfeld System）", "英國的睦鄰組織運動", "辛辛那提市的社區實驗", "聯合國的和平工作小組"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "7c146fe75f87", "answer_pdf_sha1": "cbbe7f92f516", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
